// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [selectedDay, setSelectedDay] = useState<string>('');

  useEffect(() => {
    if (!selectedDay && Array.isArray(props.forecast) && props.forecast.length > 0) {
      setSelectedDay(props.forecast[0]?.day ?? '');
    }
  }, [props.forecast, selectedDay]);

  const conditionIcon = useMemo(() => {
    const normalized = (props.condition || '').toLowerCase();
    if (normalized.includes('sun')) return '☀️';
    if (normalized.includes('cloud')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('mist') || normalized.includes('fog') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  }, [props.condition]);

  const tempUnit = (props.unit || '').toUpperCase() === 'F' ? 'F' : 'C';

  const forecastItems = useMemo(() => {
    const rawForecast = Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : [];
    const normalized = rawForecast.map((item, index) => {
      const hasRequiredFields =
        typeof item.day === 'string' && item.day.trim().length > 0 &&
        typeof item.icon === 'string' && item.icon.trim().length > 0 &&
        typeof item.high === 'number' &&
        typeof item.low === 'number';

      return {
        ...item,
        index,
        isComplete: hasRequiredFields
      };
    });

    while (normalized.length < 5) {
      normalized.push({
        day: '',
        icon: '',
        high: undefined,
        low: undefined,
        index: normalized.length,
        isComplete: false
      });
    }

    return normalized;
  }, [props.forecast]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)'
        }}
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Weather
              </Text>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {props.city}
              </Heading>
            </Stack>
            <Badge variant="primary">Now</Badge>
          </Row>

          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)">
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {`${props.temperature}°${tempUnit}` }
              </Text>
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Icon name={conditionIcon} size={24} />
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {props.condition}
                </Text>
              </Row>
            </Stack>

            <Card
              padding="var(--ggui-spacing-4)"
              shadow="none"
              radius="lg"
              style={{
                background: 'var(--ggui-color-surface, #fafafa)',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
              }}
            >
              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between" gap="var(--ggui-spacing-6)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{`${props.humidity}%`}</Text>
                </Row>
                <Row justify="between" gap="var(--ggui-spacing-6)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{`${props.windSpeed} km/h`}</Text>
                </Row>
              </Stack>
            </Card>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-Day Forecast
            </Text>
            {forecastItems.length === 0 ? (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap>
                {forecastItems.map((item, index) => {
                  const dayLabel = item.day ?? `Day ${index + 1}`;
                  const iconLabel = item.icon ?? '🌤️';
                  const isActive = selectedDay === dayLabel;

                  return (
                    <Card
                      key={`${dayLabel}-${index}` }
                      as={Clickable}
                      onClick={() => setSelectedDay(dayLabel)}
                      padding="var(--ggui-spacing-2)"
                      shadow="none"
                      radius="md"
                      style={{
                        minWidth: '110px',
                        background: isActive
                          ? 'var(--ggui-color-primary-50, #f0f9ff)'
                          : 'var(--ggui-color-surface, #fafafa)',
                        border: isActive
                          ? '1px solid var(--ggui-color-primary-300, #7dd3fc)'
                          : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                      }}
                    >
                      <Stack align="center" gap="var(--ggui-spacing-1)">
                        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{dayLabel}</Text>
                        <Icon name={iconLabel} size={20} />
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {`${item.high ?? '-'}°${tempUnit} / ${item.low ?? '-'}°${tempUnit}`}
                        </Text>
                      </Stack>
                    </Card>
                  );
                })}
              </Row>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

