import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const totalSteps = 5;
  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];
  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
  const hasValidSatisfactionScale = safeSatisfactionLabels.length > 0;

  const nameError = useMemo(() => {
    if (!nameTouched) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, nameTouched]);

  const emailError = useMemo(() => {
    if (!emailTouched) return '';
    if (!email.trim()) return 'Email is required.';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email, emailTouched]);

  const isStepValid = useMemo(() => {
    if (step === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return Boolean(name.trim()) && emailRegex.test(email.trim());
    }
    if (step === 2) return hasValidSatisfactionScale && Boolean(satisfaction);
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    return true;
  }, [step, name, email, satisfaction, comments]);

  const progressValue = useMemo(() => (step / totalSteps) * 100, [step]);

  const satisfactionOptions = useMemo(
    () =>
      safeSatisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [safeSatisfactionLabels]
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (!isStepValid) return;
    setSubmitError('');
    setStep((prev) => Math.min(prev + 1, totalSteps));
  }, [isStepValid]);

  const handleBack = useCallback(() => {
    setSubmitError('');
    setStep((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleSubmit = useCallback(() => {
    if (!name.trim() || !email.trim() || !satisfaction) {
      setSubmitError('Please complete required fields before submitting.');
      return;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email.trim())) {
      setSubmitError('Please provide a valid email address.');
      return;
    }
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    });
    setSubmitError('');
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        border
        radius="lg"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Survey
              </Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!nameTouched) setNameTouched(true);
                }}
                required
                error={nameError}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!emailTouched) setEmailTouched(true);
                }}
                required
                error={emailError}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              {safeSatisfactionLabels.length === 0 ? (
                <Alert variant="warning" title="Rating options unavailable">
                  Satisfaction labels are missing. Please provide at least one label.
                </Alert>
              ) : (
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                  error={!satisfaction ? 'Please choose a rating before continuing.' : ''}
                />
              )}
            </Stack>
          )}


          {step === 3 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Which features are you interested in?
              </Text>
              {safeFeatureOptions.length === 0 ? (
                <Alert variant="info" title="No features available">
                  Feature options are currently unavailable.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {safeFeatureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))}
                </Stack>
              )}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <TextArea
                label="Additional comments (optional)"
                value={comments}
                onChange={setComments}
                maxLength={500}
                showCount
                rows={6}
                helperText="Share any additional feedback."
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {comments.length}/500 characters
              </Text>
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review your answers</Heading>
              <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                  <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                  <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction ? `${Number(satisfaction)} - ${safeSatisfactionLabels[Number(satisfaction) - 1]}` : '-'}</Text>
                  <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                  <Text><Text is="span" weight="semibold">Comments:</Text> {comments || 'No comments provided'}</Text>
                </Stack>
              </Card>
              {submitError && <Alert variant="error" title="Submission error">{submitError}</Alert>}
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-2)" />
          <Row justify="between" align="center">
            <Button
              variant="ghost"
              onPress={handleBack}
              disabled={step === 1}
            >
              Back
            </Button>
            {step < totalSteps ? (
              <Button
                variant="primary"
                onPress={handleNext}
                disabled={!isStepValid}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onPress={handleSubmit}>
                Submit
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

