  halogen: 'var(--ggui-color-warning-50, #fffbeb)',
  'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
  lanthanide: 'var(--ggui-color-success-50, #f0fdf4)',
  actinide: 'var(--ggui-color-error-50, #fef2f2)',
  unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
};

const FALLBACK_CATEGORY_COLORS: string[] = [
  'var(--ggui-color-primary-50, #f0f9ff)',
  'var(--ggui-color-primary-100, #e0f2fe)',
  'var(--ggui-color-primary-200, #bae6fd)',
  'var(--ggui-color-success-100, #dcfce7)',
  'var(--ggui-color-warning-100, #fef3c7)',
  'var(--ggui-color-info-100, #cffafe)',
  'var(--ggui-color-error-100, #fee2e2)',
  'var(--ggui-color-surfaceVariant, #f4f4f5)',
];

function normalizeCategoryKey(category?: string): string {
  const normalized = (category ?? 'unknown').toLowerCase().trim().replace(/[-_]+/g, ' ').replace(/\s+/g, ' ');
  if (normalized === 'noble gases') return 'noble gas';
  return normalized || 'unknown';
}

function getFallbackCategoryColor(categoryKey: string): string {
  let hash = 0;
  for (let i = 0; i < categoryKey.length; i += 1) {
    hash = (hash * 31 + categoryKey.charCodeAt(i)) >>> 0;
  }
  return FALLBACK_CATEGORY_COLORS[hash % FALLBACK_CATEGORY_COLORS.length];
}

function getCategoryColor(category?: string): string {
  const normalized = normalizeCategoryKey(category);
  return CATEGORY_COLORS[normalized] ?? getFallbackCategoryColor(normalized);
}

