                {typingVisible ? `${typingState?.sender} is typing...` : ' '}
              </Text>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>
        </Card>

        <Card border radius="lg" padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Box
              background="var(--ggui-color-surface, #fafafa)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              padding="var(--ggui-spacing-4)"
            >
              <Box
                style={{
                  maxHeight: '60vh',
                  overflowY: 'auto',
                }}
                ref={scrollRef}
              >
                {(groupedMessages ?? []).length === 0 ? (
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    No messages yet.
                  </Text>
                ) : (
                  <Stack gap="var(--ggui-spacing-4)">
                    {(groupedMessages ?? []).map((group, groupIndex) => {
                      const isCurrentUser = group.sender === props.currentUser;
                      return (
                        <Stack key={`${group.sender ?? 'unknown'}-${groupIndex}`} align={isCurrentUser ? 'end' : 'start'} gap="var(--ggui-spacing-2)">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {group.sender || 'Unknown'}
                          </Text>
                          <Stack gap="var(--ggui-spacing-2)" align={isCurrentUser ? 'end' : 'start'}>
                            {group.items.map((m, msgIndex) => (
                              <Box
                                key={`${groupIndex}-${msgIndex}-${m.timestamp ?? ''}`}
padding="var(--ggui-spacing-2)"
                                borderRadius="var(--ggui-shape-radius-md, 8px)"
                                background={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-600, #0284c7)'
                                    : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                                }
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="body"
                                    color={
                                      isCurrentUser
                                        ? 'var(--ggui-color-surface, #fafafa)'
                                        : 'var(--ggui-color-onSurface, #18181b)'
                                    }
                                  >
                                    {m.text || ''}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={
                                      isCurrentUser
                                        ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                        : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                    }
                                    align={isCurrentUser ? 'right' : 'left'}
                                  >
                                    {formatTime(m.timestamp)}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        </Stack>
                      );
                    })}
                    {typingVisible ? (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {typingState?.sender} is typing...
                      </Text>
                    ) : null}
                  </Stack>
                )}
              </Box>
            </Box>

            <Row gap="var(--ggui-spacing-2)" align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message..."
                  value={messageText}
                  onChange={setMessageText}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter') {
                      event.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </Box>
              <Button variant="primary" onClick={handleSend} disabled={messageText.trim().length === 0}>
                Send
              </Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

