type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [displayStocks, setDisplayStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Record<string, boolean>>({});

  useEffect(() => {
    setDisplayStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) return;
    setDisplayStocks((prev) => {
      const current = prev ?? [];
      const index = current.findIndex((stock) => stock.symbol === priceUpdate.latest?.symbol);
      if (index === -1) {
        return [
          ...current,
          {
            symbol: priceUpdate.latest?.symbol,
            name: priceUpdate.latest?.symbol,
            price: priceUpdate.latest?.price,
            change: priceUpdate.latest?.change,
            changePercent: priceUpdate.latest?.changePercent,
          },
        ];
      }
      const next = [...current];
      next[index] = {
        ...next[index],
        price: priceUpdate.latest?.price ?? next[index].price,
        change: priceUpdate.latest?.change ?? next[index].change,
        changePercent: priceUpdate.latest?.changePercent ?? next[index].changePercent,
      };
      return next;
    });

    setLastUpdated(new Date());
    setFlashingSymbols((prev) => ({ ...prev, [String(priceUpdate.latest?.symbol)]: true }));
    const timeout = setTimeout(() => {
      setFlashingSymbols((prev) => ({ ...prev, [String(priceUpdate.latest?.symbol)]: false }));
    }, 600);
    return () => clearTimeout(timeout);
  }, [priceUpdate.latest]);

  const formattedUpdatedTime = useMemo(() => {
    return lastUpdated.toLocaleTimeString();
  }, [lastUpdated]);

  const statusVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') return 'success';
    if (marketStatus.latest?.status === 'closed') return 'error';
    return 'warning';
  }, [marketStatus.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          border
          radius="lg"
          shadow="sm"
        >
          <Row align="center" justify="between" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formattedUpdatedTime}
              </Text>
            </Stack>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Badge variant={statusVariant}>
                {marketStatus.latest?.status ?? 'pre-market'}
              </Badge>
            </Row>
          </Row>
        </Card>

        {(displayStocks ?? []).length === 0 ? (
          <Alert variant="info" title="No stock data">
            Waiting for stock data to display.
          </Alert>
        ) : (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, minmax(0, 1fr))',
              gap: 'var(--ggui-spacing-4)',
            }}
          >
            {(displayStocks ?? []).map((stock, index) => {
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const arrow = isPositive ? '▲' : '▼';
              const symbol = stock.symbol ?? `stock-${index}`;
              const color = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-4)"
                  radius="lg"
                  shadow="sm"
                  border
                  style={{
                    borderColor: color,
                    borderWidth: '1px',
                    borderStyle: 'solid',
                  }}
                >
                  <Box
                    background={flashingSymbols[symbol] ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    padding="var(--ggui-spacing-4)"
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol ?? 'N/A'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                      <Divider margin="var(--ggui-spacing-2)" />
                      <Row justify="between" align="center">
                        <Text variant="bodySmall" color={color}>
                          {change >= 0 ? '+' : ''}{change.toFixed(2)}
                        </Text>
                        <Text variant="bodySmall" weight="medium" color={color}>
                          {arrow} {changePercent >= 0 ? '+' : ''}{changePercent.toFixed(2)}%
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>

  );
}

