  }, [email]);

  const step1Valid = useMemo(() => {
    return name.trim().length > 0 && email.trim().length > 0 && emailIsValid && avatar.trim().length > 0;
  }, [name, email, emailIsValid, avatar]);

  const step2Valid = useMemo(() => {
    return role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  }, [role, theme]);

  const canGoNext = useMemo(() => {
    if (currentStep === 1) return step1Valid;
    if (currentStep === 2) return step2Valid;
    return true;
  }, [currentStep, step1Valid, step2Valid]);
  const progressValue = useMemo(() => (currentStep / 3) * 100, [currentStep]);

  const goNext = useCallback(() => {
    if (!canGoNext) return;
    setCurrentStep((prev) => Math.min(3, prev + 1));
  }, [canGoNext]);

  const goBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  }, []);

  const handleComplete = useCallback(() => {
    if (!step1Valid || !step2Valid) return;
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
    setSubmitted(true);
  }, [step1Valid, step2Valid, name, email, avatar, role, emailNotifications, theme, props]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="lg"
          border
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">
                Step {currentStep} of 3
              </Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Complete your profile setup in three quick steps.
            </Text>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          radius="lg"
          border
        >
          <Box
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            padding="var(--ggui-spacing-4)"
          >
            <Stack gap="var(--ggui-spacing-4)">
              <Box
                key={currentStep}
                style={{ animation: 'ggui-slideInUp 200ms ease-out' }}
              >
                {currentStep === 1 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Profile Setup</Heading>
                    <Input
                      label="Name"
                      value={name}
                      onChange={setName}
                      required
                      placeholder="Enter your name"
                      error={name.trim().length === 0 ? 'Name is required.' : ''}
                    />
                    <Input
                      label="Email"
                      type="email"
                      value={email}
                      onChange={setEmail}
                      required
                      placeholder="you@example.com"
                      error={email.trim().length === 0 ? 'Email is required.' : !emailIsValid ? 'Please enter a valid email.' : ''}
                    />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label">Choose an avatar</Text>
                      <Row gap="var(--ggui-spacing-2)" wrap>
                        {(props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '😎', '🚀', '🌟']).map((emoji) => (
                          <Card
                            key={emoji}
                            as={Clickable}
                            onClick={() => setAvatar(emoji)}
                            padding="var(--ggui-spacing-2)"
                            border
                            radius="md"
                            shadow="none"
                          >
                            <Box
                              background={avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surface, #fafafa)'}
                              borderRadius="var(--ggui-shape-radius-sm, 4px)"
                              padding="var(--ggui-spacing-2)"
                            >
                              <Text size="xl" align="center">{emoji}</Text>
                            </Box>
                          </Card>
                        ))}
                      </Row>
                    </Stack>
                  </Stack>
                )}

                {currentStep === 2 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Preferences</Heading>
                    <Select
                      label="Role"
                      value={role}
                      onChange={setRole}
                      placeholder="Select your role"
                      options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((item) => ({ value: item, label: item }))}
                      required
                      error={role.trim().length === 0 ? 'Role is required.' : ''}
                    />
                    <Toggle
                      label="Enable email notifications"
                      checked={emailNotifications}
                      onChange={setEmailNotifications}
                      size="md"
                    />
                    <Toggle
                      label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}` }
                      checked={theme === 'dark'}
                      onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                      size="md"
                    />
                  </Stack>
                )}

                {currentStep === 3 && (
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Review & Confirm</Heading>
                    <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                        <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                        <Text><Text is="span" weight="semibold">Avatar:</Text> {avatar}</Text>
                        <Text><Text is="span" weight="semibold">Role:</Text> {role || '-'}</Text>
                        <Text><Text is="span" weight="semibold">Email Notifications:</Text> {emailNotifications ? 'On' : 'Off'}</Text>
                        <Text><Text is="span" weight="semibold">Theme:</Text> {theme}</Text>
                      </Stack>
                    </Card>
                  </Stack>
                )}
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button
              variant="ghost"
              onClick={goBack}
              disabled={currentStep === 1}
            >
              Back
            </Button>

            <Row gap="var(--ggui-spacing-2)">
              {currentStep < 3 && (
                <Button
                  variant="primary"
                  onClick={goNext}
                  disabled={!canGoNext}
                >
                  Next
                </Button>
              )}
              {currentStep === 3 && (
                <>
                  <Button variant="outline" onClick={goBack}>
                    Go Back
                  </Button>
                  <Button
                    variant="primary"
                    onClick={handleComplete}
                    disabled={!step1Valid || !step2Valid}
                  >
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>

        {submitted && (
          <Alert variant="success" title="Setup complete">
            Your onboarding details were submitted successfully.
          </Alert>
        )}
      </Stack>
    </Container>

  );
}
